    _ = market
    var indexPrice any = this.SafeNumber(ticker, "index_price")
    var marketType any = Ternary(IsTrue((!IsEqual(indexPrice, nil))), "contract", "spot")
    var marketId any = this.SafeStringUpper2(ticker, "symbol", "instrument_id")
