func  (this *DigifinexCore) ParseTransfer(transfer any, optionalArgs ...any) any  {
    //
    // transfer between spot, margin and OTC
    //
    //     {
    //         "code": 0
    //     }
    //
    // transfer between spot and swap
    //
    //     {
    //         "code": 0,
    //         "data": {
    //             "type": 2,
    //             "currency": "USDT",
    //             "transfer_amount": "5"
    //         }
    //     }
    //
    // fetchTransfers
    //
    //     {
    //         "transfer_id": 130524,
    //         "type": 1,
    //         "currency": "USDT",
    //         "amount": "24",
    //         "timestamp": 1666505659000
    //     }
    //
    currency := GetArg(optionalArgs, 0, nil)
    _ = currency
    var fromAccount any = nil
    var toAccount any = nil
    var data any = this.SafeDict(transfer, "data", transfer)
    var typeVar any = this.SafeInteger(data, "type")
    if IsTrue(IsEqual(typeVar, 1)) {
        fromAccount = "spot"
        toAccount = "swap"
    } else if IsTrue(IsEqual(typeVar, 2)) {
        fromAccount = "swap"
        toAccount = "spot"
    }
    var timestamp any = this.SafeInteger(transfer, "timestamp")
    return map[string]any {
        "info": transfer,
        "id": this.SafeString(transfer, "transfer_id"),
        "timestamp": timestamp,
        "datetime": this.Iso8601(timestamp),
        "currency": this.SafeCurrencyCode(this.SafeString(data, "currency"), currency),
        "amount": this.SafeNumber2(data, "amount", "transfer_amount"),
        "fromAccount": fromAccount,
        "toAccount": toAccount,
        "status": this.ParseTransferStatus(this.SafeString(transfer, "code")),
    }
}
