                AddElementToObject(request, "type", Ternary(IsTrue(toSwap), 1, 2)) // 1 = spot to swap, 2 = swap to spot
                AddElementToObject(request, "currency", currencyId)
                AddElementToObject(request, "transfer_amount", amountString)
                //
                //     {
                //         "code": 0,
                //         "data": {
